let maxNum = 1, sizeNum = 80,length = 0


var data = []
var options = {
    min: 0,
    max: 12000,
    size: 12
}

const filterValue = 200


var isShadow = true
var canvas = document.createElement("canvas");
// document.body.appendChild(canvas)
// const width = 10, height = 16
const width = 64, height = 64
canvas.width = width * 64
canvas.height = height * 64


options.size = canvas.width / 22


function jet(min, max, x) {
    let red, g, blue;
    let dv;
    red = 1.0;
    g = 1.0;
    blue = 1.0;
    if (x < min) {
        x = min;
    }
    if (x > max) {
        x = max;
    }
    dv = max - min;
    if (x < min + 0.25 * dv) {
        // red = 0;
        // g = 0;
        // blue = 0;

        red = 0;
        g = (4 * (x - min)) / dv;
    } else if (x < min + 0.5 * dv) {
        red = 0;
        blue = 1 + (4 * (min + 0.25 * dv - x)) / dv;
    } else if (x < min + 0.75 * dv) {
        red = (4 * (x - min - 0.5 * dv)) / dv;
        blue = 0;
    } else {
        g = 1 + (4 * (min + 0.75 * dv - x)) / dv;
        blue = 0;
    }
    var rgba = new Array();
    rgba[0] = 255 * red;
    rgba[1] = 255 * g;
    rgba[2] = 255 * blue;
    rgba[3] = 1;
    return rgba;
}

// min <= x <= max
function getRandomIntInclusive(min, max) {
    min = Math.ceil(min);
    max = Math.floor(max);
    return Math.floor(Math.random() * (max - min + 1)) + min;
}



// 生成随机数据
function generateData(arr) {
 


   let resData = arr


    const data = []
    const count = 32
    console.log()
    const max = Math.max(...resData)
    options.max = max * maxNum
    options.size = sizeNum
    for (let i = 0; i < height; i++) {
        for (let j = 0; j < width; j++) {
            let obj = {}
            obj.x = i * canvas.width / width
            obj.y = j * canvas.height / height
            obj.value = resData[i * width + j]
            data.push(obj)
        }

    }
    return data
}





// 构造一个离屏canvas
function Canvas(width, height) {
    let canvas = document.createElement('canvas')
    canvas.width = width
    canvas.height = height
    return canvas
}

// 画圆
function createCircle(size, value) {
    let shadowBlur = size / 2
    let r2 = size + shadowBlur
    let offsetDistance = 10000

    let circle = new Canvas(r2 * 2, r2 * 2)
    let context = circle.getContext('2d')

    // 模糊效果程度
    if (isShadow) context.shadowBlur = shadowBlur;
    context.shadowColor = 'black'
    context.shadowOffsetX = context.shadowOffsetY = offsetDistance

    context.beginPath()
    context.arc(r2 - offsetDistance, r2 - offsetDistance, size, 0, Math.PI * 2, true)
    context.closePath()
    context.fillStyle = `rgb(${jet(value)})`
    context.fill()
    return circle
}

function draw(context, data) {
    // console.log(options)
    let circle = createCircle(options.size)
    let circleHalfWidth = circle.width / 2
    let circleHalfHeight = circle.height / 2

    // 按透明度分类
    let dataOrderByAlpha = {}
    data.forEach((item) => {
        let alpha = Math.min(1, item.value / options.max).toFixed(2)
        dataOrderByAlpha[alpha] = dataOrderByAlpha[alpha] || []
        dataOrderByAlpha[alpha].push(item)
    })

    // 绘制不同透明度的圆形
    for (let i in dataOrderByAlpha) {
        if (isNaN(Number(i))) continue;
        let _data = dataOrderByAlpha[i]
        context.beginPath()
        context.globalAlpha = i
        _data.forEach((item) => {
            context.drawImage(circle, item.x - circleHalfWidth, item.y - circleHalfHeight)
        })
    }
    // 圆形着色
    let intensity = new (Intensity)()
    let colored = context.getImageData(0, 0, context.canvas.width, context.canvas.height)
    const heatmap = colorize(colored.data, intensity.getImageData())

    function addEdgeBorder(coloredData, intensityData, width, height, threshold = 1) {
        const newData = new Uint8ClampedArray(coloredData.length);

        console.log(intensityData)

        for (let y = 1; y < height - 1; y++) {
            for (let x = 1; x < width - 1; x++) {
                const idx = (y * width + x) * 4;
                const v = intensityData[idx]; // 灰度值（0-255）

                // // 取邻域值
                const left = intensityData[(y * width + (x - 1)) * 4];
                const right = intensityData[(y * width + (x + 1)) * 4];
                const up = intensityData[((y - 1) * width + x) * 4];
                const down = intensityData[((y + 1) * width + x) * 4];

                // const v = intensityData[idx + 1] + intensityData[idx + 2] + intensityData[idx + 3]

                // const left = intensityData[(y * width + (x - 1)) * 4 + 1] + intensityData[(y * width + (x - 1)) * 4 + 2] + intensityData[(y * width + (x - 1)) * 4 + 3];
                // const right = intensityData[(y * width + (x + 1)) * 4 + 1] + intensityData[(y * width + (x + 1)) * 4 + 2] + intensityData[(y * width + (x + 1)) * 4 + 3];
                // const up = intensityData[((y - 1) * width + x) * 4 + 1] + intensityData[((y - 1) * width + x) * 4 + 2] + intensityData[((y - 1) * width + x) * 4 + 3];
                // const down = intensityData[((y + 1) * width + x) * 4 + 1] + intensityData[((y + 1) * width + x) * 4 + 2] + intensityData[((y + 1) * width + x) * 4 + 3];

                // 判断是否是边缘
                const diff =
                    Math.abs(v - left) +
                    // Math.abs(v - right)
                    +
                    // Math.abs(v - up) +
                    Math.abs(v - down);

                // const diff = Math.abs(v - heatMap[y * width + x + 1]) + Math.abs(v - heatMap[(y + 1) * width + x]);


                // 37,51,107

                // console.log('diff:', diff);
                if (diff > threshold) {
                    // 边缘像素：黑边或指定颜色
                    newData[idx] = 37;     // R
                    newData[idx + 1] = 51; // G
                    newData[idx + 2] = 107; // B
                    newData[idx + 3] = 255;
                    // console.log(v, left, right, up, down, diff)
                } else {
                    // 非边缘：保留原色
                    newData[idx] = coloredData[idx];
                    newData[idx + 1] = coloredData[idx + 1];
                    newData[idx + 2] = coloredData[idx + 2];
                    newData[idx + 3] = coloredData[idx + 3];
                }
            }
        }

        return newData;
    }

    function addEdgeBorderSobel(coloredData, heatMap, width, height, threshold = 1) {
        const newData = new Uint8ClampedArray(coloredData.length);
        const gx = [[-1, 0, 1], [-2, 0, 2], [-1, 0, 1]];  // Sobel X
        const gy = [[-1, -2, -1], [0, 0, 0], [1, 2, 1]];  // Sobel Y

        for (let y = 1; y < height - 1; y++) {
            for (let x = 1; x < width - 1; x++) {
                let sx = 0, sy = 0;

                // 计算梯度
                for (let j = -1; j <= 1; j++) {
                    for (let i = -1; i <= 1; i++) {
                        const v = heatMap[(y + j) * width + (x + i)];
                        sx += gx[j + 1][i + 1] * v;
                        sy += gy[j + 1][i + 1] * v;
                    }
                }

                // 计算梯度幅值
                const mag = Math.sqrt(sx * sx + sy * sy);
                const idx = (y * width + x) * 4;

                if (mag > threshold) {
                    newData[idx] = 0;    // 黑色边框
                    newData[idx + 1] = 0;
                    newData[idx + 2] = 0;
                    newData[idx + 3] = 255; // 不透明
                } else {
                    newData[idx] = coloredData[idx];
                    newData[idx + 1] = coloredData[idx + 1];
                    newData[idx + 2] = coloredData[idx + 2];
                    newData[idx + 3] = coloredData[idx + 3];
                }
            }
        }

        return newData;
    }

    let intensityData = intensity.getImageData()
    console.log(colored.data, intensityData)
    const edged = addEdgeBorder(colored.data, heatmap, context.canvas.width, context.canvas.height, 0.0001);

    context.clearRect(0, 0, context.canvas.width, context.canvas.height)
    // context.fillStyle = '#666'
    // context.fillRect(0, 0, context.canvas.width, context.canvas.height)
    // console.log(colored)
    context.fillStyle = '#666'
    context.fillRect(0, 0, context.canvas.width, context.canvas.height)


    context.clearRect(0, 0, context.canvas.width, context.canvas.height)
    // context.putImageData(colored, 0, 0)
    context.putImageData(new ImageData(edged, context.canvas.width, context.canvas.height), 0, 0);

    // applySharpen(context, canvas.width, canvas.height);
}
function applySharpen(context, width, height) {
    // 获取原始图像数据
    let originalImageData = context.getImageData(0, 0, width, height);
    let originalPixels = originalImageData.data;

    // 创建一个用于存放处理后的图像数据的 ImageData 对象
    let outputImageData = context.createImageData(width, height);
    let outputPixels = outputImageData.data;

    const kernel = [
        0, -1, 0,
        -1, 5, -1,
        0, -1, 0,
    ];

    const kernelSize = Math.sqrt(kernel.length);
    const halfKernelSize = Math.floor(kernelSize / 2);

    for (let y = 0; y < height; y++) {
        for (let x = 0; x < width; x++) {
            let r = 0, g = 0, b = 0;

            for (let ky = 0; ky < kernelSize; ky++) {
                for (let kx = 0; kx < kernelSize; kx++) {
                    // 考虑边缘像素
                    let pixelY = y + ky - halfKernelSize;
                    let pixelX = x + kx - halfKernelSize;

                    if (pixelY < 0 || pixelY >= height || pixelX < 0 || pixelX >= width) continue;

                    // 卷积计算
                    let offset = (pixelY * width + pixelX) * 4;
                    let weight = kernel[ky * kernelSize + kx];

                    r += originalPixels[offset] * weight;
                    g += originalPixels[offset + 1] * weight;
                    b += originalPixels[offset + 2] * weight;
                }
            }

            let destOffset = (y * width + x) * 4;
            outputPixels[destOffset] = r;
            outputPixels[destOffset + 1] = g;
            outputPixels[destOffset + 2] = b;
            outputPixels[destOffset + 3] = originalPixels[destOffset + 3]; // 保持相同的 alpha 值
        }
    }

    // 将处理后的图像数据绘制回画布
    context.putImageData(outputImageData, 0, 0);
}


